# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <cstring>

constexpr int GRID = 30;
constexpr int TURNS = 300;
constexpr int WALL_ROW = 7;
constexpr int GAP_CENTER = 15;
constexpr int GAP_HALF = 2;

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

struct Pt { int r, c; };
bool operator==(Pt a, Pt b) { return a.r == b.r && a.c == b.c; }

bool wall[31][31];
int N, M;
std::vector<Pt> pets;
std::vector<int> pet_types;
std::vector<Pt> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_at(int r, int c) {
    for (auto& p : pets)
        if (p.r == r && p.c == c) return true;
    return false;
}

bool pet_adjacent_or_at(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

bool human_at(int r, int c, int exclude = -1) {
    for (int j = 0; j < M; j++) {
        if (j == exclude) continue;
        if (humans[j].r == r && humans[j].c == c) return true;
    }
    return false;
}

int bfs_dist[31][31];
Pt bfs_prev[31][31];

char move_toward(Pt from, Pt to) {
    if (from.r == to.r && from.c == to.c) return '.';
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Pt> q;
    bfs_dist[from.r][from.c] = 0;
    q.push(from);
    while (!q.empty()) {
        Pt cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || bfs_dist[nr][nc] != -1) continue;
            bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
            bfs_prev[nr][nc] = cur;
            if (nr == to.r && nc == to.c) {
                Pt step = to;
                while (!(bfs_prev[step.r][step.c] == from)) {
                    step = bfs_prev[step.r][step.c];
                }
                for (int k = 0; k < 4; k++) {
                    if (from.r + DR[k] == step.r && from.c + DC[k] == step.c)
                        return MOVE_CH[k];
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

bool is_gap_cell(int c, int seal_stage) {
    int gap_min = GAP_CENTER - GAP_HALF + seal_stage;
    int gap_max = GAP_CENTER + GAP_HALF - seal_stage;
    return c >= gap_min && c <= gap_max;
}

bool is_wall_target(int r, int c, int seal_stage) {
    if (r != WALL_ROW) return false;
    if (c < 1 || c > GRID) return false;
    if (is_gap_cell(c, seal_stage)) return false;
    return true;
}

int count_pets_interior() {
    int count = 0;
    for (auto& p : pets) {
        if (p.r < WALL_ROW) count++;
    }
    return count;
}

bool pet_in_interior_or_at_gap() {
    for (auto& p : pets) {
        if (p.r < WALL_ROW) return true;
        if (p.r == WALL_ROW) {
            for (int c = 1; c <= GRID; c++) {
                if (!wall[WALL_ROW][c] && p.c == c) return true;
            }
        }
    }
    return false;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }
    memset(wall, false, sizeof(wall));

    // seal_stage: 0 = gap is full (5 cells: 13-17)
    //             1 = closed edges (3 cells: 14-16)
    //             2 = closed more (1 cell: 15)
    //             3 = fully sealed
    int seal_stage = 0;
    bool all_humans_inside = false;

