    // Wall cells: (WALL_ROW, c) for c=1..30, excluding current gap

    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');

        // Check if all humans are inside (rows 1 to WALL_ROW-1)
        all_humans_inside = true;
        for (int i = 0; i < M; i++) {
