                        for (int i = 0; i < M; i++) {
                            if (actions[i] != '.') continue;
                            if (humans[i].r == WALL_ROW + 1 && humans[i].c == c2) {
                                actions[i] = 'u';
                                sealed_c2 = true;
                                break;
                            }
