                    for (int i = 0; i < M; i++) {
                        if (actions[i] != '.') continue;
                        if (humans[i].r < WALL_ROW && std::abs(humans[i].c - c1) + std::abs(humans[i].r - (WALL_ROW-1)) <= 3) {
                            actions[i] = move_toward(humans[i], {WALL_ROW-1, c1});
                            break;
