            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || bfs_d[nr][nc] != -1) continue;
            if (nr == avoid_row) continue;
            bfs_d[nr][nc] = bfs_d[cur.r][cur.c] + 1;
            bfs_p[nr][nc] = cur;
            q.push({nr, nc});
        }
    }
    // Fallback: normal move
    return move_toward(from, to);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }
    memset(wall, false, sizeof(wall));

    // Choose wall row: we want a large safe zone above, so pick wall_row
    // such that we maximize area above while being buildable.
    // Lower wall_row = smaller safe zone but easier to clear pets
    // Higher wall_row = larger safe zone but harder to clear pets
    // Let's use wall_row = 8 for 7*30 = 210 interior cells above
    int WALL_ROW = 8;

    // Gap: columns 12-19 (8 cells wide initially)
    int gap_left = 12;
    int gap_right = 19;

    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');

        // Determine what still needs building on the wall row (excluding gap)
        std::vector<int> need_build;
        for (int c = 1; c <= GRID; c++) {
            if (c >= gap_left && c <= gap_right) continue;
            if (!wall[WALL_ROW][c]) need_build.push_back(c);
        }

        bool wall_complete = need_build.empty();

        // Check all humans above (in safe zone: rows 1 to WALL_ROW-1)
        bool all_above = true;
        for (int i = 0; i < M; i++) {
            if (humans[i].r >= WALL_ROW) { all_above = false; break; }
        }

        // Count pets in safe zone (above wall)
        int pets_above = 0;
        for (auto& p : pets) {
            if (p.r < WALL_ROW) pets_above++;
        }

        // Check if gap is fully sealed
        bool fully_sealed = true;
        for (int c = 1; c <= GRID; c++) {
            if (!wall[WALL_ROW][c]) { fully_sealed = false; break; }
        }

        if (fully_sealed) {
            // Done! Just stay.
            std::cout << actions << std::endl;
            for (int i = 0; i < N; i++) {
                std::string s; std::cin >> s;
                if (s == ".") continue;
                for (char ch : s) {
                    for (int d = 0; d < 4; d++) {
                        if (ch == MOVE_CH[d]) { pets[i].r += DR[d]; pets[i].c += DC[d]; break; }
                    }
                }
            }
            continue;
        }

        // PHASE 1: Build the wall (excluding gap)
        if (!wall_complete) {
            // Sort need_build cells and assign to humans
            // Each human finds nearest unbuilt cell
            std::vector<bool> claimed(GRID + 1, false);

            for (int i = 0; i < M; i++) {
                int best_c = -1, best_dist = 9999;
                for (int c : need_build) {
                    if (claimed[c]) continue;
                    // Best build position: above or below
                    int d1 = std::abs(humans[i].r - (WALL_ROW - 1)) + std::abs(humans[i].c - c);
                    int d2 = std::abs(humans[i].r - (WALL_ROW + 1)) + std::abs(humans[i].c - c);
                    int d = std::min(d1, d2);
                    if (d < best_dist) { best_dist = d; best_c = c; }
                }
                if (best_c == -1) continue;
                claimed[best_c] = true;

                // Can we build it now?
                bool built = false;
                if (humans[i].r == WALL_ROW - 1 && humans[i].c == best_c) {
                    if (!pet_adjacent_or_at(WALL_ROW, best_c) && !human_at(WALL_ROW, best_c, i)) {
                        actions[i] = 'd';
                        built = true;
                    }
                } else if (humans[i].r == WALL_ROW + 1 && humans[i].c == best_c) {
                    if (!pet_adjacent_or_at(WALL_ROW, best_c) && !human_at(WALL_ROW, best_c, i)) {
                        actions[i] = 'u';
                        built = true;
                    }
                } else if (humans[i].r == WALL_ROW && humans[i].c == best_c - 1) {
                    if (!pet_adjacent_or_at(WALL_ROW, best_c) && !human_at(WALL_ROW, best_c, i)) {
                        actions[i] = 'r';
                        built = true;
                    }
                } else if (humans[i].r == WALL_ROW && humans[i].c == best_c + 1) {
                    if (!pet_adjacent_or_at(WALL_ROW, best_c) && !human_at(WALL_ROW, best_c, i)) {
                        actions[i] = 'l';
                        built = true;
                    }
                }

                if (!built) {
                    // Also try to build any adjacent unbuilt wall cell opportunistically
                    bool opp = false;
                    for (int d = 0; d < 4; d++) {
                        int wr = humans[i].r + DR[d], wc = humans[i].c + DC[d];
                        if (wr != WALL_ROW) continue;
                        if (wc < 1 || wc > GRID) continue;
                        if (wall[WALL_ROW][wc]) continue;
                        if (wc >= gap_left && wc <= gap_right) continue;
                        if (pet_adjacent_or_at(wr, wc)) continue;
                        if (human_at(wr, wc, i)) continue;
                        actions[i] = BUILD_CH[d];
                        opp = true;
                        break;
                    }
                    if (!opp) {
                        // Move toward build position
                        int d1 = std::abs(humans[i].r - (WALL_ROW - 1)) + std::abs(humans[i].c - best_c);
                        int d2 = std::abs(humans[i].r - (WALL_ROW + 1)) + std::abs(humans[i].c - best_c);
                        Pt target;
                        if (d1 <= d2) target = {WALL_ROW - 1, best_c};
                        else target = {WALL_ROW + 1, best_c};
                        actions[i] = move_toward(humans[i], target);
                    }
                }
            }
        }
        // PHASE 2: Move all humans above the wall (through gap)
        else if (!all_above) {
            for (int i = 0; i < M; i++) {
                if (humans[i].r < WALL_ROW) continue; // already above
                // Navigate through gap to get above
                int mid_c = (gap_left + gap_right) / 2;
                // Find a passable gap cell
                int target_c = -1;
                for (int c = gap_left; c <= gap_right; c++) {
                    if (!wall[WALL_ROW][c]) { target_c = c; break; }
                }
                if (target_c == -1) continue; // gap sealed somehow

                if (humans[i].r == WALL_ROW && humans[i].c >= gap_left && humans[i].c <= gap_right && !wall[WALL_ROW][humans[i].c]) {
                    // On a gap cell, move up
                    actions[i] = 'U';
                } else if (humans[i].r == WALL_ROW + 1 && humans[i].c >= gap_left && humans[i].c <= gap_right) {
                    // Just below gap, move up into gap row then up again next turn
                    // Actually move up to the gap
                    if (!wall[WALL_ROW][humans[i].c]) {
                        actions[i] = 'U';
                    } else {
                        actions[i] = move_toward(humans[i], {WALL_ROW + 1, target_c});
                    }
                } else {
                    // Move toward gap entry
                    actions[i] = move_toward(humans[i], {WALL_ROW + 1, target_c});
                }
            }
        }
        // PHASE 3: Seal the gap progressively
        else {
            // All humans above. Now seal gap cells from edges inward.
            // Only seal if no pets above (or we're running out of time and should just seal anyway)
            bool should_seal = (pets_above == 0) || (turn > 250);

            if (should_seal) {
                // Find the leftmost and rightmost unsealed gap cells
                int left_gap = -1, right_gap = -1;
                for (int c = gap_left; c <= gap_right; c++) {
                    if (!wall[WALL_ROW][c]) {
                        if (left_gap == -1) left_gap = c;
                        right_gap = c;
                    }
                }

                if (left_gap != -1) {
                    // Try to seal from both sides
                    // Seal left_gap: need human at (WALL_ROW-1, left_gap)
                    bool sealed_left = false;
                    if (!pet_adjacent_or_at(WALL_ROW, left_gap) && !human_at(WALL_ROW, left_gap)) {
                        for (int i = 0; i < M; i++) {
                            if (actions[i] != '.') continue;
                            if (humans[i].r == WALL_ROW - 1 && humans[i].c == left_gap) {
                                actions[i] = 'd';
                                sealed_left = true;
                                break;
                            }
                        }
                    }

                    // Seal right_gap
                    bool sealed_right = false;
                    if (right_gap != left_gap && !pet_adjacent_or_at(WALL_ROW, right_gap) && !human_at(WALL_ROW, right_gap)) {
                        for (int i = 0; i < M; i++) {
                            if (actions[i] != '.') continue;
                            if (humans[i].r == WALL_ROW - 1 && humans[i].c == right_gap) {
                                actions[i] = 'd';
                                sealed_right = true;
                                break;
                            }
                        }
                    }

                    // Move humans toward sealing positions
                    if (!sealed_left) {
                        for (int i = 0; i < M; i++) {
                            if (actions[i] != '.') continue;
                            if (humans[i].r >= WALL_ROW) continue;
                            int d = std::abs(humans[i].r - (WALL_ROW-1)) + std::abs(humans[i].c - left_gap);
                            if (d <= 5) {
                                actions[i] = move_toward(humans[i], {WALL_ROW-1, left_gap});
                                break;
                            }
                        }
                    }
                    if (!sealed_right && right_gap != left_gap) {
                        for (int i = 0; i < M; i++) {
                            if (actions[i] != '.') continue;
                            if (humans[i].r >= WALL_ROW) continue;
                            int d = std::abs(humans[i].r - (WALL_ROW-1)) + std::abs(humans[i].c - right_gap);
                            if (d <= 5) {
                                actions[i] = move_toward(humans[i], {WALL_ROW-1, right_gap});
                                break;
                            }
                        }
                    }
                }
            } else {
                // Pets above - move humans toward gap positions for readiness
                // Also position near gap to seal quickly when pets leave
                for (int c = gap_left; c <= gap_right; c++) {
                    if (wall[WALL_ROW][c]) continue;
                    // Find nearest human not yet assigned
                    for (int i = 0; i < M; i++) {
                        if (actions[i] != '.') continue;
                        if (humans[i].r == WALL_ROW - 1 && humans[i].c == c) break; // already there
                        int d = std::abs(humans[i].r - (WALL_ROW-1)) + std::abs(humans[i].c - c);
                        if (d <= 4) {
                            actions[i] = move_toward(humans[i], {WALL_ROW-1, c});
                            break;
                        }
                    }
                }
            }
        }

        // Validate all actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == '.') continue;

            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc) || wall[nr][nc]) { actions[i] = '.'; continue; }
                // Check no build action targets this cell
                for (int j = 0; j < M; j++) {
                    if (j == i) continue;
                    char aj = actions[j];
                    if (aj == 'u' || aj == 'd' || aj == 'l' || aj == 'r') {
                        int dj = -1;
                        for (int k = 0; k < 4; k++) if (BUILD_CH[k] == aj) dj = k;
                        int wr = humans[j].r + DR[dj], wc = humans[j].c + DC[dj];
                        if (wr == nr && wc == nc) { actions[i] = '.'; break; }
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc)) { actions[i] = '.'; continue; }
                if (wall[nr][nc]) { actions[i] = '.'; continue; }
                if (pet_adjacent_or_at(nr, nc)) { actions[i] = '.'; continue; }
                if (human_at(nr, nc, i)) { actions[i] = '.'; continue; }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc)) wall[nr][nc] = true;
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    humans[i].r = nr;
                    humans[i].c = nc;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string s;
            std::cin >> s;
            if (s == ".") continue;
            for (char ch : s) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) { pets[i].r += DR[d]; pets[i].c += DC[d]; break; }
                }
            }
        }
    }

    return 0;
}
