    corners[1].size = corner_size;
    corners[1].ir_min = 1; corners[1].ir_max = corner_size;
    corners[1].ic_min = GRID - corner_size + 1; corners[1].ic_max = GRID;
    // Horizontal wall: row corner_size+1, cols GRID-corner_size to GRID
    for (int c = GRID - corner_size; c <= GRID; c++)
