# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <cstring>

constexpr int GRID = 30;
constexpr int TURNS = 300;

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

struct Pt { int r, c; };
bool operator==(Pt a, Pt b) { return a.r == b.r && a.c == b.c; }
bool operator!=(Pt a, Pt b) { return !(a == b); }

bool wall[31][31];
int N, M;
std::vector<Pt> pets;
std::vector<int> pet_types;
std::vector<Pt> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_adjacent_or_at(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

bool human_at(int r, int c, int exclude = -1) {
    for (int j = 0; j < M; j++) {
        if (j == exclude) continue;
        if (humans[j].r == r && humans[j].c == c) return true;
    }
    return false;
}

int bfs_d[31][31];
Pt bfs_p[31][31];

char move_toward(Pt from, Pt to) {
    if (from == to) return '.';
    memset(bfs_d, -1, sizeof(bfs_d));
    std::queue<Pt> q;
    bfs_d[from.r][from.c] = 0;
    q.push(from);
    while (!q.empty()) {
        Pt cur = q.front(); q.pop();
        if (cur == to) {
            Pt step = to;
            while (bfs_p[step.r][step.c] != from) {
                step = bfs_p[step.r][step.c];
            }
            for (int k = 0; k < 4; k++) {
                if (from.r + DR[k] == step.r && from.c + DC[k] == step.c)
                    return MOVE_CH[k];
            }
            return '.';
        }
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || bfs_d[nr][nc] != -1) continue;
            bfs_d[nr][nc] = bfs_d[cur.r][cur.c] + 1;
            bfs_p[nr][nc] = cur;
            q.push({nr, nc});
        }
    }
    return '.';
}

struct Enclosure {
    int ir_min, ir_max, ic_min, ic_max;
    std::vector<Pt> walls;
    Pt gate;
    Pt gate_stand;
    int gate_dir;
    Pt center;
};

bool is_interior(const Enclosure& e, int r, int c) {
    return r >= e.ir_min && r <= e.ir_max && c >= e.ic_min && c <= e.ic_max;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }
    memset(wall, false, sizeof(wall));

    int S = 10; // corner size

    // 4 corner enclosures using grid edges as 2 boundaries
    std::vector<Enclosure> encs(4);

    // Top-Left: interior [1..S] x [1..S]
    // Walls: row S+1 cols 1..S, col S+1 rows 1..S, plus corner cell (S+1, S+1)
    encs[0].ir_min = 1; encs[0].ir_max = S;
    encs[0].ic_min = 1; encs[0].ic_max = S;
    for (int c = 1; c <= S; c++) encs[0].walls.push_back({S+1, c});
    for (int r = 1; r <= S; r++) encs[0].walls.push_back({r, S+1});
    encs[0].walls.push_back({S+1, S+1});
    // Gate at corner junction - last cell to seal is (S+1, S+1)
    // But better: gate mid-wall for easier human access
    // Gate on bottom wall, column S/2
    encs[0].gate = {S+1, S/2};
    encs[0].gate_stand = {S, S/2}; // inside, looking down
    encs[0].gate_dir = 1; // 'd'
    encs[0].center = {S/2, S/2};

    // Top-Right: interior [1..S] x [GRID-S+1..GRID]
    encs[1].ir_min = 1; encs[1].ir_max = S;
    encs[1].ic_min = GRID-S+1; encs[1].ic_max = GRID;
    for (int c = GRID-S+1; c <= GRID; c++) encs[1].walls.push_back({S+1, c});
    for (int r = 1; r <= S; r++) encs[1].walls.push_back({r, GRID-S});
    encs[1].walls.push_back({S+1, GRID-S});
    encs[1].gate = {S+1, GRID-S/2};
    encs[1].gate_stand = {S, GRID-S/2};
    encs[1].gate_dir = 1; // 'd'
    encs[1].center = {S/2, GRID-S/2};

    // Bottom-Left: interior [GRID-S+1..GRID] x [1..S]
    encs[2].ir_min = GRID-S+1; encs[2].ir_max = GRID;
    encs[2].ic_min = 1; encs[2].ic_max = S;
    for (int c = 1; c <= S; c++) encs[2].walls.push_back({GRID-S, c});
    for (int r = GRID-S+1; r <= GRID; r++) encs[2].walls.push_back({r, S+1});
    encs[2].walls.push_back({GRID-S, S+1});
    encs[2].gate = {GRID-S, S/2};
    encs[2].gate_stand = {GRID-S+1, S/2};
    encs[2].gate_dir = 0; // 'u'
    encs[2].center = {GRID-S/2, S/2};

    // Bottom-Right: interior [GRID-S+1..GRID] x [GRID-S+1..GRID]
    encs[3].ir_min = GRID-S+1; encs[3].ir_max = GRID;
    encs[3].ic_min = GRID-S+1; encs[3].ic_max = GRID;
    for (int c = GRID-S+1; c <= GRID; c++) encs[3].walls.push_back({GRID-S, c});
    for (int r = GRID-S+1; r <= GRID; r++) encs[3].walls.push_back({r, GRID-S});
    encs[3].walls.push_back({GRID-S, GRID-S});
    encs[3].gate = {GRID-S, GRID-S/2};
    encs[3].gate_stand = {GRID-S+1, GRID-S/2};
    encs[3].gate_dir = 0; // 'u'
    encs[3].center = {GRID-S/2, GRID-S/2};

    // Deduplicate walls
    for (auto& e : encs) {
        std::sort(e.walls.begin(), e.walls.end(), [](Pt a, Pt b){
            return a.r < b.r || (a.r == b.r && a.c < b.c);
        });
        e.walls.erase(std::unique(e.walls.begin(), e.walls.end(), [](Pt a, Pt b){
            return a == b;
        }), e.walls.end());
    }

    // Assign humans to enclosures using greedy nearest approach
    // but ensure at least 1 per corner
    std::vector<int> human_enc(M);
    std::vector<int> enc_count(4, 0);

    // Compute distances for all human-corner pairs
    struct Assignment { int dist; int human; int corner; };
    std::vector<Assignment> assignments;
    for (int i = 0; i < M; i++) {
        for (int ci = 0; ci < 4; ci++) {
            int d = std::abs(humans[i].r - encs[ci].center.r) + std::abs(humans[i].c - encs[ci].center.c);
            assignments.push_back({d, i, ci});
        }
    }
    std::sort(assignments.begin(), assignments.end(), [](const Assignment& a, const Assignment& b){
        return a.dist < b.dist;
    });

    std::vector<bool> assigned(M, false);
    // First pass: ensure each corner gets at least 1
    for (int ci = 0; ci < 4; ci++) {
        int best_h = -1, best_d = 9999;
        for (int i = 0; i < M; i++) {
            if (assigned[i]) continue;
            int d = std::abs(humans[i].r - encs[ci].center.r) + std::abs(humans[i].c - encs[ci].center.c);
            if (d < best_d) { best_d = d; best_h = i; }
        }
        if (best_h >= 0) {
            human_enc[best_h] = ci;
            enc_count[ci]++;
            assigned[best_h] = true;
        }
    }
    // Assign remaining humans to nearest corner
    for (auto& a : assignments) {
        if (assigned[a.human]) continue;
        human_enc[a.human] = a.corner;
        enc_count[a.corner]++;
        assigned[a.human] = true;
    }

    std::vector<int> phase(M, 0);

    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');

        for (int i = 0; i < M; i++) {
            int ci = human_enc[i];
            Enclosure& e = encs[ci];

            int unbuilt = 0;
            for (auto& w : e.walls) {
                if (w == e.gate) continue;
                if (!wall[w.r][w.c]) unbuilt++;
            }
            bool gate_sealed = wall[e.gate.r][e.gate.c];

            if (gate_sealed) { phase[i] = 3; continue; }
            if (unbuilt == 0) {
                if (is_interior(e, humans[i].r, humans[i].c)) phase[i] = 2;
                else phase[i] = 1;
            } else {
                phase[i] = 0;
            }

            if (phase[i] == 3) continue;

            if (phase[i] == 2) {
                if (humans[i] != e.gate_stand) {
                    actions[i] = move_toward(humans[i], e.gate_stand);
                    continue;
                }
                bool pets_inside = false;
                for (auto& p : pets) {
                    if (is_interior(e, p.r, p.c)) { pets_inside = true; break; }
                }
                // Also check no pet at gate position or adjacent
                if (!pets_inside && !pet_adjacent_or_at(e.gate.r, e.gate.c) && !human_at(e.gate.r, e.gate.c, i)) {
                    actions[i] = BUILD_CH[e.gate_dir];
                }
                continue;
            }

            if (phase[i] == 1) {
                // Move toward gate (which is open), then to gate_stand
                // First get to gate position, then to gate_stand
                if (!is_interior(e, humans[i].r, humans[i].c)) {
                    // Move to gate first
                    actions[i] = move_toward(humans[i], e.gate);
                } else {
                    actions[i] = move_toward(humans[i], e.gate_stand);
                }
                continue;
            }

            // Phase 0: Build walls
            // Try to build any adjacent wall cell first (opportunistic)
            bool built = false;
            for (int d = 0; d < 4; d++) {
                int wr = humans[i].r + DR[d], wc = humans[i].c + DC[d];
                if (!valid(wr, wc) || wall[wr][wc]) continue;
                bool is_our = false;
                for (auto& w : e.walls) {
                    if (w == e.gate) continue;
                    if (w.r == wr && w.c == wc) { is_our = true; break; }
                }
                if (!is_our) continue;
                if (pet_adjacent_or_at(wr, wc)) continue;
                if (human_at(wr, wc, i)) continue;
                actions[i] = BUILD_CH[d];
                built = true;
                break;
            }
            if (built) continue;

            // Move to nearest unbuilt wall build position
            Pt best_stand = {-1, -1};
            int best_cost = 9999;
            for (auto& w : e.walls) {
                if (w == e.gate || wall[w.r][w.c]) continue;
                for (int d = 0; d < 4; d++) {
                    int sr = w.r + DR[d], sc = w.c + DC[d];
                    if (!valid(sr, sc) || wall[sr][sc]) continue;
                    int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                    if (dist < best_cost) { best_cost = dist; best_stand = {sr, sc}; }
                }
            }
            if (best_stand.r != -1) {
                actions[i] = move_toward(humans[i], best_stand);
            }
        }

        // Validate
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == '.') continue;
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc) || wall[nr][nc]) { actions[i] = '.'; continue; }
                for (int j = 0; j < M; j++) {
                    if (j == i) continue;
                    char aj = actions[j];
                    if (aj == 'u' || aj == 'd' || aj == 'l' || aj == 'r') {
                        int dj = -1;
                        for (int k = 0; k < 4; k++) if (BUILD_CH[k] == aj) dj = k;
                        int wr = humans[j].r + DR[dj], wc = humans[j].c + DC[dj];
                        if (wr == nr && wc == nc) { actions[i] = '.'; break; }
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc)) { actions[i] = '.'; continue; }
                if (wall[nr][nc]) { actions[i] = '.'; continue; }
                if (pet_adjacent_or_at(nr, nc)) { actions[i] = '.'; continue; }
                if (human_at(nr, nc, i)) { actions[i] = '.'; continue; }
            }
        }

        std::cout << actions << std::endl;

        // Apply
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc)) wall[nr][nc] = true;
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    humans[i].r = nr;
                    humans[i].c = nc;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string s;
            std::cin >> s;
            if (s == ".") continue;
            for (char ch : s) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) { pets[i].r += DR[d]; pets[i].c += DC[d]; break; }
                }
            }
        }
    }

    return 0;
}
