                if (!pets_inside && !pet_adjacent_or_at(e.gate.r, e.gate.c) && !human_at(e.gate.r, e.gate.c, i)) {
                    actions[i] = BUILD_CH[e.gate_dir];
                }
                continue;
            }

            if (phase[i] == 1) {
                // Move toward gate (which is open), then to gate_stand
                // First get to gate position, then to gate_stand
                if (!is_interior(e, humans[i].r, humans[i].c)) {
                    // Move to gate first
                    actions[i] = move_toward(humans[i], e.gate);
                } else {
                    actions[i] = move_toward(humans[i], e.gate_stand);
                }
                continue;
            }

